295	// routing at the `handler`, which in most cases is another chi.Router. As a result,
296	// if you define two Mount() routes on the exact same pattern the mount will panic.
297	func (mx *Mux) Mount(pattern string, handler http.Handler) {
298		if handler == nil {
299			panic(fmt.Sprintf("chi: attempting to Mount() a nil handler on '%s'", pattern))
300		}
