361	// Match searches the routing tree for a handler that matches the method/path.
362	// It's similar to routing a http request, but without executing the handler
363	// thereafter.
364	//
365	// Note: the *Context state is updated during execution, so manage
366	// the state carefully or make a NewRouteContext().
367	func (mx *Mux) Match(rctx *Context, method, path string) bool {
368		m, ok := methodMap[method]
369		if !ok {
370			return false
371		}
372	
373		node, _, h := mx.tree.FindRoute(rctx, m, path)
374	
375		if node != nil && node.subroutes != nil {
376			rctx.RoutePath = mx.nextRoutePath(rctx)
377			return node.subroutes.Match(rctx, method, rctx.RoutePath)
378		}
379	
380		return h != nil
381	}
