426	// routeHTTP routes a http.Request through the Mux routing tree to serve
427	// the matching handler for a particular http method.
428	func (mx *Mux) routeHTTP(w http.ResponseWriter, r *http.Request) {
429		// Grab the route context object
430		rctx := r.Context().Value(RouteCtxKey).(*Context)
431	
432		// The request routing path
433		routePath := rctx.RoutePath
434		if routePath == "" {
435			if r.URL.RawPath != "" {
436				routePath = r.URL.RawPath
437			} else {
438				routePath = r.URL.Path
439			}
440			if routePath == "" {
441				routePath = "/"
442			}
443		}
444	
445		// Check if method is supported by chi
446		if rctx.RouteMethod == "" {
447			rctx.RouteMethod = r.Method
448		}
449		method, ok := methodMap[rctx.RouteMethod]
450		if !ok {
451			mx.MethodNotAllowedHandler().ServeHTTP(w, r)
452			return
453		}
454	
455		// Find the route
456		if _, _, h := mx.tree.FindRoute(rctx, method, routePath); h != nil {
457			h.ServeHTTP(w, r)
458			return
459		}
460		if rctx.methodNotAllowed {
461			mx.MethodNotAllowedHandler(rctx.methodsAllowed...).ServeHTTP(w, r)
462		} else {
463			mx.NotFoundHandler().ServeHTTP(w, r)
464		}
465	}
